// src/components/MentorDashboard.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  listProjectsForMentor,
  listRequestsForMentor,
  listAvailabilityForMentor,
  createAvailability,
  updateAvailability,
  deleteAvailability,
  updateMentorRequest,
} from "../api/resources";
import { getUserId } from "../api/users";
import logout from "../utils/logout";
import "./mentorDashboard.css"; // keep your CSS

export default function MentorDashboard() {
  const navigate = useNavigate();
  const mentorId = getUserId();
  const [activeTab, setActiveTab] = useState("dashboard");
  const [mentorRequests, setMentorRequests] = useState([]);
  const [projects, setProjects] = useState([]);
  const [slots, setSlots] = useState([]);
  const [newSlot, setNewSlot] = useState({ day: "", start_time: "", end_time: "", location: "" });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!mentorId) { navigate("/login"); return; }
    const load = async () => {
      try {
        const [reqRes, projRes, slotRes] = await Promise.all([
          listRequestsForMentor(mentorId),
          listProjectsForMentor(mentorId),
          listAvailabilityForMentor(mentorId),
        ]);
        setMentorRequests(reqRes.data || []);
        setProjects(projRes.data || []);
        setSlots(slotRes.data || []);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [mentorId, navigate]);

  const acceptRequest = async (req) => {
    await updateMentorRequest(req.id, { status: "accepted" });
    // Reload both requests and projects after accept
    const [reqRes, projRes] = await Promise.all([
      listRequestsForMentor(mentorId),
      listProjectsForMentor(mentorId),
    ]);
    setMentorRequests(reqRes.data || []);
    setProjects(projRes.data || []);
    alert("Request accepted");
  };

  const rejectRequest = async (req) => {
    await updateMentorRequest(req.id, { status: "rejected" });
    const reqRes = await listRequestsForMentor(mentorId);
    setMentorRequests(reqRes.data || []);
    alert("Request rejected");
  };

  const addSlot = async () => {
    const { day, start_time, end_time, location } = newSlot;
    if (!day || !start_time || !end_time) return alert("Fill date and time");
    await createAvailability({ day, start_time, end_time, location });
    const slotRes = await listAvailabilityForMentor(mentorId);
    setSlots(slotRes.data || []);
    setNewSlot({ day: "", start_time: "", end_time: "", location: "" });
  };

  if (loading) return <div className="loading">Loading...</div>;

  // Keep your existing JSX blocks (tabs, cards, lists). Below is only a minimal scaffold.
  return (
    <div className="mentor-dashboard">
      <div className="dashboard-header">
        <h1>Mentor Dashboard</h1>
        <button onClick={() => logout(navigate)}>Logout</button>
      </div>

      <div className="tabs">
        <button className={activeTab==='dashboard'?'active':''} onClick={()=>setActiveTab('dashboard')}>Dashboard</button>
        <button className={activeTab==='students'?'active':''} onClick={()=>setActiveTab('students')}>Students</button>
        <button className={activeTab==='submissions'?'active':''} onClick={()=>setActiveTab('submissions')}>Submissions</button>
        <button className={activeTab==='availability'?'active':''} onClick={()=>setActiveTab('availability')}>Availability</button>
        <button className={activeTab==='specialties'?'active':''} onClick={()=>setActiveTab('specialties')}>Specialties</button>
      </div>

      <div className="main-content">
        {activeTab === "submissions" && (
          <div className="projects-section">
            <h2>Pending Requests</h2>
            {mentorRequests.length === 0 ? <p>No pending requests.</p> : (
              <div className="project-cards">
                {mentorRequests.map((r)=>(
                  <div className="project-card" key={r.id}>
                    <h3>{r.project_title || "Untitled Project"}</h3>
                    <p><b>Student:</b> {r.student_name} ({r.student_email})</p>
                    <p><b>Status:</b> {r.status}</p>
                    {r.status === "pending" && (
                      <div className="project-actions">
                        <button className="approve-btn" onClick={()=>acceptRequest(r)}>Accept</button>
                        <button className="reject-btn" onClick={()=>rejectRequest(r)}>Reject</button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}

            <h3 style={{marginTop:20}}>Approved Projects</h3>
            {projects.length === 0 ? <p>No approved projects.</p> : (
              <div className="project-cards">
                {projects.map((p)=>(
                  <div className="project-card" key={p.id}>
                    <h3>{p.title}</h3>
                    <p><b>Status:</b> {p.status}</p>
                    <p><b>Description:</b> {p.description}</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === "availability" && (
          <div className="availability-section">
            <h2>Your Meeting Slots</h2>

            <div className="add-slot" style={{background:'#fff',padding:16,border:'1px solid #e0e0e0',borderRadius:8,marginBottom:16}}>
              <h3 style={{marginTop:0}}>Add Offline Slot</h3>
              <div style={{display:'flex',gap:12,flexWrap:'wrap'}}>
                <div><label>Date</label><br/>
                  <input type="date" value={newSlot.day} onChange={(e)=>setNewSlot(s=>({...s, day:e.target.value}))}/>
                </div>
                <div><label>Start</label><br/>
                  <input type="time" value={newSlot.start_time} onChange={(e)=>setNewSlot(s=>({...s, start_time:e.target.value}))}/>
                </div>
                <div><label>End</label><br/>
                  <input type="time" value={newSlot.end_time} onChange={(e)=>setNewSlot(s=>({...s, end_time:e.target.value}))}/>
                </div>
                <div><label>Location</label><br/>
                  <input type="text" value={newSlot.location} placeholder="Lab 3, Block A"
                         onChange={(e)=>setNewSlot(s=>({...s, location:e.target.value}))}/>
                </div>
                <div style={{alignSelf:'flex-end'}}>
                  <button className="approve-btn" onClick={addSlot}>Add Slot</button>
                </div>
              </div>
            </div>

            <div className="slot-grid">
              {slots.length === 0 ? <p>No slots added.</p> : slots.map(slot=>(
                <div className={`slot-card ${slot.status}`} key={slot.id}>
                  <p><b>{slot.day}</b> {slot.start_time}-{slot.end_time}</p>
                  {slot.location && <p><b>Location:</b> {slot.location}</p>}
                  <span style={{color: slot.status==='booked' ? '#FF6B00' : '#4caf50'}}>
                    {slot.status === 'booked' ? 'Booked' : 'Free'}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Keep your other tabs (dashboard/students/specialties) UI exactly as before; only swap data sources if needed */}
      </div>
    </div>
  );
}
